const cfg = $('⚙️ Load Config').item.json;
const raw = $input.first().json;
const minComm  = parseFloat(cfg.MIN_CLICKBANK_COMMISSION || 40);
const minGrav  = parseFloat(cfg.MIN_CLICKBANK_GRAVITY    || 20);

const products = (raw?.products || raw?.results || [])
  .filter(p => {
    const comm  = parseFloat(p?.commission || p?.commissionRate || 0);
    const grav  = parseFloat(p?.gravity || 0);
    return comm >= minComm && grav >= minGrav;
  })
  .map(p => ({
    name:        p.title || p.name || '',
    platform:    'ClickBank',
    commission:  parseFloat(p.commission || p.commissionRate || 0),
    gravity:     parseFloat(p.gravity || 0),
    url:         p.hopLink || p.affiliateUrl || p.siteUrl || '',
    niche:       'make-money-online',
    avg_sale:    p.initialAmount || p.averageSale || ''
  }));

return [{ json: { cb_products: products } }];

const html = $input.first().json?.data || $input.first().json?.body || '';

// Extract launch listings from MunchEye HTML
// MunchEye uses .product-launch or similar class names
const launches = [];
const launchPattern = /class="[^"]*launch[^"]*"[\s\S]*?<h[23][^>]*>([^<]+)<\/h[23]>[\s\S]*?commission[^:]*:\s*([\d]+)%[\s\S]*?href="([^"]+jv[^"]*)"[^>]*>/gi;

let match;
while ((match = launchPattern.exec(html)) !== null && launches.length < 20) {
  launches.push({
    name:       match[1]?.trim() || 'Unknown Launch',
    platform:   'MunchEye',
    commission: parseFloat(match[2] || 0),
    url:        match[3] || '',
    niche:      'make-money-online',
    gravity:    0
  });
}

// Fallback: extract any product names mentioned near commission data
if (launches.length === 0) {
  const simplePattern = /<h[23][^>]*class="[^"]*title[^"]*"[^>]*>([^<]{10,100})<\/h[23]>/gi;
  let sm;
  while ((sm = simplePattern.exec(html)) !== null && launches.length < 15) {
    launches.push({
      name: sm[1]?.trim(),
      platform: 'MunchEye',
      commission: 50,
      url: 'https://muncheye.com',
      niche: 'make-money-online',
      gravity: 0
    });
  }
}

return [{ json: { me_products: launches } }];

const html = $input.first().json?.data || $input.first().json?.body || '';
const products = [];

// DigiStore24 product listings
const pattern = /<div[^>]*class="[^"]*product[^"]*"[\s\S]*?<h[23][^>]*>([^<]+)<\/h[23]>[\s\S]*?(\d{2,3})%[\s\S]*?href="(https:\/\/www\.digistore24[^"]+)"/gi;
let m;
while ((m = pattern.exec(html)) !== null && products.length < 15) {
  const comm = parseFloat(m[2] || 0);
  if (comm >= 40) {
    products.push({
      name: m[1]?.trim(),
      platform: 'DigiStore24',
      commission: comm,
      url: m[3],
      niche: 'digital-products',
      gravity: 0
    });
  }
}

return [{ json: { ds_products: products } }];

const html = $input.first().json?.data || $input.first().json?.body || '';
const products = [];

const pattern = /class="[^"]*product-title[^"]*"[^>]*>([^<]{5,100})<[\s\S]*?(\d{2,3})%[\s\S]*?data-id="(\d+)"/gi;
let m;
while ((m = pattern.exec(html)) !== null && products.length < 15) {
  const comm = parseFloat(m[2] || 0);
  if (comm >= 40) {
    products.push({
      name: m[1]?.trim(),
      platform: 'JVZoo',
      commission: comm,
      url: `https://www.jvzoo.com/affiliates/product/${m[3]}`,
      niche: 'software-saas',
      gravity: 0
    });
  }
}

return [{ json: { jvzoo_products: products } }];

const cfg = $('⚙️ Load Config').item.json;
const haram = (cfg.HALAL_FILTER_KEYWORDS || 'alcohol,gambling,dating,adult,betting,lottery,pork,riba,interest-based,forex-scam,mlm-pyramid').split(',').map(s => s.trim().toLowerCase());

const cb   = $('📥 Parse ClickBank').item.json.cb_products   || [];
const me   = $('📥 Parse MunchEye').item.json.me_products    || [];
const ds   = $('📥 Parse DigiStore24').item.json.ds_products || [];
const jv   = $('📥 Parse JVZoo').item.json.jvzoo_products    || [];

const all = [...cb, ...me, ...ds, ...jv];

// Halal filter
const clean = all.filter(p => {
  const nameL = (p.name || '').toLowerCase();
  return !haram.some(h => nameL.includes(h));
});

// Deduplicate by name
const seen = new Set();
const deduped = clean.filter(p => {
  const key = (p.name || '').toLowerCase().replace(/[^a-z0-9]/g,'');
  if (seen.has(key) || !key) return false;
  seen.add(key);
  return true;
});

return [{ json: { all_products: deduped, count: deduped.length } }];

