const cfg      = $('⚙️ Load Config').item.json;
const products = $('🔀 Merge All + Halal Filter').item.json.all_products || [];
const raw      = $input.first().json.message?.content || '[]';

let scores = [];
try {
  const match = raw.match(/\[([\s\S]*?)\](?!\s*[a-z])/i);
  scores = JSON.parse(match ? '[' + match[1] + ']' : raw);
} catch(e) {
  scores = products.slice(0, 15).map(p => ({ name: p.name, ai_score: 5, relevance: 'Relevant to blog', pitch: 'My how-to blog covers ' + p.niche + '. I have engaged readers looking for tools. I want to promote ' + p.name + ' because it aligns with my audience needs.' }));
}

// Merge scores with product data
const enriched = scores.map(s => {
  const product = products.find(p => p.name?.toLowerCase().includes((s.name || '').toLowerCase().split(' ')[0])) || {};
  return {
    Program_Name:    s.name || product.name || '',
    Platform:        product.platform || '',
    Commission_Pct:  product.commission || 0,
    Gravity_EPC:     product.gravity || 0,
    Niche:           product.niche || '',
    Application_URL: product.url || '',
    AI_Score:        s.ai_score || 5,
    AI_Pitch:        s.pitch || '',
    Relevance:       s.relevance || '',
    Halal_Flag:      'Yes',
    Date_Found:      new Date().toISOString().split('T')[0],
    Status:          'New'
  };
}).sort((a, b) => b.AI_Score - a.AI_Score);

// Build Telegram message (top 10)
const top10 = enriched.slice(0, 10);
const lines = top10.map((p, i) =>
  `${i+1}. <b>${p.Program_Name}</b>\n   Platform: ${p.Platform} | Commission: ${p.Commission_Pct}% | Score: ${p.AI_Score}/10\n   Apply: ${p.Application_URL}`
);

const msg = `💰 <b>HowTo-Genie: Weekly Affiliate Digest</b>\n📅 ${new Date().toLocaleDateString('en-MY', {timeZone: cfg.TIMEZONE || 'Asia/Kuala_Lumpur'})}\n\nTop ${top10.length} programs found this week:\n\n${lines.join('\n\n')}\n\n📋 Full list + pitches saved to Affiliate Programs sheet.`;

return [{ json: { all_scored: enriched, telegram_message: msg, chat_id: cfg.TELEGRAM_CHAT_ID } }];

const cfg      = $('⚙️ Load Config').item.json;
const incoming = $('🔀 Merge All + Halal Filter').item.json.all_products || [];

// Read existing affiliate sheet to get already-known program names
let existingNames = new Set();
try {
  const existing = $('📊 Read Existing Affiliates')?.all() || [];
  for (const row of existing) {
    const name = (row.json?.Program_Name || row.json?.program_name || '').toLowerCase().replace(/[^a-z0-9]/g,'');
    if (name) existingNames.add(name);
  }
} catch(e) {}

const fresh = incoming.filter(p => {
  const key = (p.name || '').toLowerCase().replace(/[^a-z0-9]/g,'');
  return key && !existingNames.has(key);
});

return [{ json: { all_products: fresh, count: fresh.length, skipped: incoming.length - fresh.length } }];
